const items = $input.all();

function trim(v) {
  return String(v ?? '').trim();
}

function normalizePhone(v) {
  const raw = trim(v).replace(/[^\d+]/g, '');
  if (!raw) return '';
  const canonical = raw.startsWith('+62') ? `62${raw.slice(3)}` : raw;
  return canonical.startsWith('0') ? `62${canonical.slice(1)}` : canonical;
}

return items.map((item) => {
  const payload = item.json || {};
  const to = normalizePhone(payload.to);
  const message = trim(payload.message);
  const eticket = trim(payload.eticket_no);
  const studentName = trim(payload.student_name);

  if (!to) {
    throw new Error('Payload invalid: field "to" wajib diisi.');
  }
  if (!message) {
    throw new Error('Payload invalid: field "message" wajib diisi.');
  }

  return {
    json: {
      to,
      message,
      eticket_no: eticket || null,
      student_name: studentName || null,
      source: trim(payload.source) || 'ppdb_register',
      received_at: new Date().toISOString()
    }
  };
});

const items = $input.all();

const provider = String($env.N8N_WA_PROVIDER || 'waha').trim().toLowerCase();
const token = String($env.N8N_WA_TOKEN || '').trim();
const genericEndpoint = String($env.N8N_WA_ENDPOINT || '').trim();
const session = String($env.N8N_WA_SESSION || 'default').trim() || 'default';

function providerEndpoint(name) {
  if (name === 'fonnte') return genericEndpoint || 'https://api.fonnte.com/send';
  if (name === 'wablas') return genericEndpoint;
  if (name === 'waha') return genericEndpoint || 'https://waha.devlike.pro/api/sendText';
  return genericEndpoint;
}

function asChatId(phone) {
  return String(phone || '').includes('@') ? String(phone || '') : `${phone}@c.us`;
}

async function sendOne(item) {
  const endpoint = providerEndpoint(provider);
  if (!endpoint) {
    return {
      ...item,
      sent: false,
      reason: 'missing_endpoint',
      provider
    };
  }

  if ((provider === 'fonnte' || provider === 'wablas') && !token) {
    return {
      ...item,
      sent: false,
      reason: 'missing_token',
      provider
    };
  }

  let request;
  if (provider === 'fonnte') {
    const form = new URLSearchParams({ target: item.to, message: item.message }).toString();
    request = {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': token
      },
      body: form
    };
  } else if (provider === 'wablas') {
    request = {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token
      },
      body: JSON.stringify({ phone: item.to, message: item.message })
    };
  } else if (provider === 'waha') {
    request = {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { 'X-Api-Key': token } : {})
      },
      body: JSON.stringify({
        session,
        chatId: asChatId(item.to),
        text: item.message
      })
    };
  } else {
    request = {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { Authorization: `Bearer ${token}` } : {})
      },
      body: JSON.stringify({
        to: item.to,
        message: item.message,
        eticket_no: item.eticket_no,
        student_name: item.student_name,
        source: item.source
      })
    };
  }

  try {
    const response = await fetch(endpoint, request);
    const text = await response.text().catch(() => '');
    return {
      ...item,
      sent: response.ok,
      provider,
      reason: response.ok ? 'sent' : `http_${response.status}`,
      gateway_status: response.status,
      gateway_response: text ? text.slice(0, 500) : null
    };
  } catch (error) {
    return {
      ...item,
      sent: false,
      provider,
      reason: 'network_error',
      gateway_status: 0,
      gateway_response: String(error?.message || error || 'unknown_error').slice(0, 500)
    };
  }
}

const out = [];
for (const entry of items) {
  const result = await sendOne(entry.json || {});
  out.push({ json: result });
}
return out;
